export function getAllWords(): Word[] {
  return LESSONS.flatMap(l => l.words);
}

export function getLevelData(levelNum: number) {
  const baseXP = 10;
  const xp = Math.min(baseXP + Math.floor(levelNum / 10), 50);

  // Orden de progresión de dificultad:
  // Niveles 1-50: lecciones 1-50 (básico)
  // Niveles 51-100: lecciones 101-150 (intermedio-bajo)
  // Niveles 101-150: lecciones 51-100 (intermedio)
  // Niveles 151-200: lecciones 151-200 (intermedio-alto)
  // Niveles 201-250: lecciones 301-350 (avanzado-cotidiano)
  // Niveles 251-300: lecciones 201-250 (avanzado)
  // Niveles 301-350: lecciones 351-400 (avanzado-especializado)
  // Niveles 351-400: lecciones 251-300 (muy avanzado)
  // Niveles 401-500: ciclar sobre las 400 lecciones
  const PROGRESSION: number[] = [];
  for (let i = 0; i < 50; i++) PROGRESSION.push(i);        // 0-49: lecciones 1-50
  for (let i = 100; i < 150; i++) PROGRESSION.push(i);     // 50-99: lecciones 101-150
  for (let i = 50; i < 100; i++) PROGRESSION.push(i);      // 100-149: lecciones 51-100
  for (let i = 150; i < 200; i++) PROGRESSION.push(i);     // 150-199: lecciones 151-200
  for (let i = 300; i < 350; i++) PROGRESSION.push(i);     // 200-249: lecciones 301-350
  for (let i = 200; i < 250; i++) PROGRESSION.push(i);     // 250-299: lecciones 201-250
  for (let i = 350; i < 400; i++) PROGRESSION.push(i);     // 300-349: lecciones 351-400
  for (let i = 250; i < 300; i++) PROGRESSION.push(i);     // 350-399: lecciones 251-300

  if (levelNum <= PROGRESSION.length) {
    const lessonIdx = PROGRESSION[levelNum - 1];
    return { ...LESSONS[lessonIdx], id: levelNum, xp };
  }
  // Niveles 401-500: ciclar sobre las 400 lecciones
  const lessonIndex = (levelNum - 1) % LESSONS.length;
  const base = LESSONS[lessonIndex];
  const cycle = Math.floor((levelNum - 1) / LESSONS.length);
  const suffixes = ['', ' II', ' III', ' IV', ' V'];
  return {
    id: levelNum,
    name: base.name + (suffixes[cycle] || ` ${cycle + 1}`),
    words: base.words,
    color: base.color,
    xp,
  };
}

export function getLevelIcon(level: number): string {
  const icons = ['📖','💬','📝','🎯','⭐','🏆','💡','🔤','📚','✏️',
                 '🌟','🚀','💪','🎨','🌈','🔬','🏅','🎓','💼','🌍',
                 '🎭','🎪','🎡','🎢','🎠','🏰','🌉','🗽','🎌','🏝️'];
  return icons[(level - 1) % icons.length];
}

export function getTodayKey(): string {
  const today = new Date();
  return `${today.getFullYear()}-${today.getMonth() + 1}-${today.getDate()}`;
}

export function getDailyWords(): Word[] {
  const today = new Date();
  const dayOfYear = Math.floor((today.getTime() - new Date(today.getFullYear(), 0, 0).getTime()) / (1000 * 60 * 60 * 24));
  const startLesson = dayOfYear % 30;
  const dailyWords: Word[] = [];
  for (let i = 0; i < 3; i++) {
    const lessonIndex = (startLesson + i) % 30;
    dailyWords.push(...LESSONS[lessonIndex].words);
  }
  return dailyWords.slice(0, 30);
}
